# ── Client-side tool-calling passthrough (operator 2026-06-15, Zen smart-window) ──
# An external OpenAI client (Zen browser "smart window", an IDE assistant, etc.)
# that supplies its OWN tools[] expects the standard OpenAI contract: the model
# RETURNS tool_calls which the CLIENT executes (Zen's get_page_content /
# get_open_tabs / run_search run IN THE BROWSER) and feeds back as role:tool
# messages. MiOS's orchestration (refine/council/swarm + server-side _VERB_CATALOG
# execution) is the WRONG shape for this -- it drops the client tools as
# "hallucinated", tries to run them server-side (impossible; they live in the
# browser), and never relays tool_calls back. So when a request carries client
# tools, bypass orchestration ENTIRELY and proxy it verbatim to a tool-capable
# backend, relaying tool_calls (SSE deltas + non-stream) unmodified -- the
# structural twin of _vision_complete. Researched + code-grounded 2026-06-15
# (workflow zen-clienttools-a2a-research): A2A/passports are the wrong tool here;
# this transparent passthrough is the fix. SSOT: mios.toml [ai].client_tools_*.
# DEDICATED backend knobs (NOT BACKEND/BACKEND_MODEL) so the relay never inherits
# the stale gemma4:12b drift; default granite4.1:8b on the keyless :11450 lane
# (verified tool-capable); repoint to mios-heavy (:11441) for harder routing.
CLIENT_TOOLS_PASSTHROUGH = os.environ.get(
    "MIOS_AGENT_PIPE_CLIENT_TOOLS_PASSTHROUGH", "true"
).strip().lower() in {"1", "true", "yes", "on"}
_TOOL_BACKEND = os.environ.get(
    "MIOS_AGENT_PIPE_TOOL_BACKEND", "http://localhost:11450/v1").rstrip("/")
_TOOL_BACKEND_MODEL = os.environ.get(
    "MIOS_AGENT_PIPE_TOOL_BACKEND_MODEL", "granite4.1:8b")
# Heavy-lane PREFERENCE for the client-tools tool loop (the agentic surface that
# fronts the Hermes desktop app + Zen). The SGLang heavy lane runs a REASONING model
# (Qwen3) -> real thinking + reliable tool-use; the light lane (granite) is weak but
# always-up/low-VRAM. Prefer heavy WHEN it is serving, fall back to light when it is
# down (e.g. gaming/VRAM) -- so "SGLang for all agents" holds when the GPU is free and
# the agentic surface NEVER hard-fails when it isn't. Health probe cached for the TTL.
_TOOL_BACKEND_HEAVY = os.environ.get(
    "MIOS_AGENT_PIPE_TOOL_BACKEND_HEAVY", "http://localhost:11441/v1").rstrip("/")
_TOOL_BACKEND_HEAVY_MODEL = os.environ.get(
    "MIOS_AGENT_PIPE_TOOL_BACKEND_HEAVY_MODEL", "mios-heavy")
_HEAVY_PROBE_TTL = float(os.environ.get("MIOS_AGENT_PIPE_HEAVY_PROBE_TTL", "30"))
_heavy_probe = {"ok": False, "ts": -1e9}


async def _heavy_lane_up() -> bool:
    """Is the SGLang heavy lane serving right now? Cached for _HEAVY_PROBE_TTL s so we
    probe at most once per window, never per request."""
    import time as _t
    now = _t.monotonic()
    if (now - _heavy_probe["ts"]) < _HEAVY_PROBE_TTL:
        return _heavy_probe["ok"]
    ok = False
    try:
        client = await _get_client()
        r = await client.get(f"{_TOOL_BACKEND_HEAVY}/models", timeout=2.0)
        ok = (r.status_code == 200)
    except Exception:  # noqa: BLE001 -- any failure => heavy is down, use light
        ok = False
    _heavy_probe["ok"] = ok
    _heavy_probe["ts"] = now
    return ok


_LANE_RESOLVER = None


def _lane_resolver():
    """WS-1 unified lane resolver (mios_lanes), built LAZILY from SSOT so _toml_section
    / _get_client are defined, then cached. ONE place a model lane is chosen: the
    [ai].heavy_engine-preferred heavy lane, then the other heavy lane, then the always-on
    light lane, with a per-lane cooldown so a dead lane fails over (never 404s). Collapses
    the two 'mios-heavy' lanes (SGLang :11441 + vLLM :11440) behind one selector."""
    global _LANE_RESOLVER
    if _LANE_RESOLVER is not None:
        return _LANE_RESOLVER
    try:
        _ai = _toml_section("ai")
    except Exception:  # noqa: BLE001 -- degrade to env/defaults
        _ai = {}
    heavy_engine = (os.environ.get("MIOS_AGENT_PIPE_HEAVY_ENGINE")
                    or str(_ai.get("heavy_engine", "sglang"))).strip()
    _vllm_url = os.environ.get("MIOS_AGENT_PIPE_TOOL_BACKEND_VLLM",
                               "http://localhost:11440/v1").rstrip("/")
    _vllm_model = os.environ.get("MIOS_AGENT_PIPE_TOOL_BACKEND_VLLM_MODEL",
                                 _TOOL_BACKEND_HEAVY_MODEL)
    lanes = {
        "light":  mios_lanes.Lane("light",  _TOOL_BACKEND,       _TOOL_BACKEND_MODEL),
        "sglang": mios_lanes.Lane("sglang", _TOOL_BACKEND_HEAVY, _TOOL_BACKEND_HEAVY_MODEL),
        "vllm":   mios_lanes.Lane("vllm",   _vllm_url,           _vllm_model),
    }
    chain = mios_lanes.build_chain(heavy_engine, lanes.keys())

    async def _probe(url: str) -> bool:
        client = await _get_client()
        r = await client.get(f"{url}/models", timeout=2.0)
        return r.status_code == 200

    _LANE_RESOLVER = mios_lanes.LaneResolver(
        lanes, {"heavy": chain, "tool": chain}, _probe,
        ttl=_HEAVY_PROBE_TTL,
        cooldown=float(os.environ.get("MIOS_AGENT_PIPE_LANE_COOLDOWN", "60")))
    try:
        log.info("lane resolver: heavy_engine=%s chain=%s", heavy_engine, chain)
    except Exception:  # noqa: BLE001
        pass
    return _LANE_RESOLVER


async def _pick_tool_backend() -> tuple:
    """(url, model) for the client-tools loop -- delegated to the WS-1 unified lane
    resolver: the preferred heavy reasoner when reachable, else the other heavy lane,
    else the always-on light lane (with per-lane cooldown so a dead lane fails over,
    never 404s). Degrade-open: any resolver error falls back to the legacy heavy/light
    probe so the agentic surface never hard-fails."""
    try:
        lane = await _lane_resolver().pick("tool")
        if lane is not None:
            return lane.url, lane.model
    except Exception as _e:  # noqa: BLE001 -- degrade to the legacy probe
        log.debug("lane resolver failed (-> legacy pick): %s", _e)
    if await _heavy_lane_up():
        return _TOOL_BACKEND_HEAVY, _TOOL_BACKEND_HEAVY_MODEL
    return _TOOL_BACKEND, _TOOL_BACKEND_MODEL
